import{_ as e,o as i,c as l,ae as t}from"./chunks/framework.CRIdhvba.js";const h=JSON.parse('{"title":"数据库原理 · 第 1 章 事务与并发控制概览","description":"","frontmatter":{"title":"数据库原理 · 第 1 章 事务与并发控制概览"},"headers":[],"relativePath":"career/backend/db-dev/db-theory/index.md","filePath":"career/backend/db-dev/db-theory/index.md"}'),r={name:"career/backend/db-dev/db-theory/index.md"};function o(n,a,d,s,c,p){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="数据库原理-·-第-1-章-事务与并发控制概览" tabindex="-1">数据库原理 · 第 1 章 事务与并发控制概览 <a class="header-anchor" href="#数据库原理-·-第-1-章-事务与并发控制概览" aria-label="Permalink to &quot;数据库原理 · 第 1 章 事务与并发控制概览&quot;">​</a></h1><p>在数据库开发工程师的日常工作中，「事务是否正确」「并发是否安全」是最核心的问题之一。本章作为数据库原理的开篇，将从宏观视角介绍这些概念。</p><h2 id="_1-1-事务-acid-特性" tabindex="-1">1.1 事务 ACID 特性 <a class="header-anchor" href="#_1-1-事务-acid-特性" aria-label="Permalink to &quot;1.1 事务 ACID 特性&quot;">​</a></h2><p>一个事务（Transaction）通常被期望满足 ACID 四大特性：</p><ul><li><strong>原子性（Atomicity）</strong>：事务中的操作要么全部成功，要么全部回滚。</li><li><strong>一致性（Consistency）</strong>：事务前后数据应满足预定义的约束（如外键、唯一约束、业务不变量）。</li><li><strong>隔离性（Isolation）</strong>：并发事务之间互不干扰，视觉上仿佛是串行执行。</li><li><strong>持久性（Durability）</strong>：事务一旦提交，其结果应被持久保存，即使系统宕机也能恢复。</li></ul><p>后续章节会结合日志与存储引擎实现，解释数据库是如何「保证」这些特性的。</p><h2 id="_1-2-并发异常与隔离级别" tabindex="-1">1.2 并发异常与隔离级别 <a class="header-anchor" href="#_1-2-并发异常与隔离级别" aria-label="Permalink to &quot;1.2 并发异常与隔离级别&quot;">​</a></h2><p>在没有任何控制的情况下，并发事务会带来：</p><ul><li>脏读（Dirty Read）</li><li>不可重复读（Non-repeatable Read）</li><li>幻读（Phantom Read）</li></ul><p>典型的 SQL 标准隔离级别包括：</p><ul><li>READ UNCOMMITTED</li><li>READ COMMITTED</li><li>REPEATABLE READ</li><li>SERIALIZABLE</li></ul><p>不同数据库在实现这些隔离级别时可能不完全一致，数据库开发工程师需要了解目标系统（如 MySQL InnoDB）的具体行为。</p><h2 id="_1-3-后续学习指引" tabindex="-1">1.3 后续学习指引 <a class="header-anchor" href="#_1-3-后续学习指引" aria-label="Permalink to &quot;1.3 后续学习指引&quot;">​</a></h2><p>在后续小节中，你将进一步学习：</p><ul><li>锁的类型（行锁、表锁、意向锁等）；</li><li>MVCC 多版本并发控制的整体思路；</li><li>InnoDB 如何结合 Undo Log 与 Read View 实现快照读；</li><li>常见并发问题在 SQL 层面的表现与排查思路。</li></ul><p>掌握这些内容后，你能更自信地解释「为什么会出现这个锁等待/死锁」，而不仅仅停留在试错式调参。</p>',16)])])}const u=e(r,[["render",o]]);export{h as __pageData,u as default};
